var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"토너먼트의 최종 승자는 미리네★스타라이트와 조호진 선수가 되었습니다.","JPN":"トーナメントの最終勝者はマリ★スターライトとイトウ・マユミ選手です。","ENG":"The tournament's champions are Mi Rinae★Starlight and Cho Hojin.","TWN":"淘汰賽的最終贏家是宓璃奈★星光和趙鎬眞選手。"},"stage":{"bg":"SKY_NIGHT","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"저게 바로 랭킹 1위의 실력! 엄청난 경기였어요!","JPN":"あれがランキング1位の実力！　すごい試合でした。","ENG":"This is the strength of the top ranker! What an incredible performance!","TWN":"這就是排名第一的實力！真是一場驚人的比賽！"},"stage":{"bg":"SKY_NIGHT","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L8_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_DOOM","text":{"KOREA":"역시…… 역부족이었던 건가…….","JPN":"やはり……力不足だったか……","ENG":"I suppose... it was not enough...","TWN":"果然……還是力不從心嗎……"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_DOOM","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_DOOM","text":{"KOREA":"허나 후회는 없다. 처음으로 강자와 동등한 위치에서 싸웠으니…….","JPN":"しかし後悔はない。初めて強者と肩を並べて戦えたからな……","ENG":"Yet, I have no regrets. For the first time, I have fought on equal footing with a formidable foe...","TWN":"但是我不後悔，因為我第一次與強者進行了對等的戰鬥……"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_DOOM","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_DOOM","text":{"KOREA":"보여다오……. 이 마카를 쓰러트린 자의 얼굴을…….","JPN":"見せてくれ……このミカを倒した者の顔を……","ENG":"Show me your face... the one who has defeated me, Mika★Apocalypse...","TWN":"讓我看看……打倒米卡的人是誰……"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"좋은 승부였다. 개네들이 잘 가르치긴 하는 갑네.","JPN":"ええ勝負やった。あいつらもええ教育しとるんやな。","ENG":"Good fight. I see y'all learned a lot from the two.","TWN":"是一場很精彩的對決，教得還真不錯啊。"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"와~ 솔직히 1등까지 하게 될 줄은 몰랐어요! \xA0","JPN":"わあ～正直優勝できるとは思いませんでした！\xA0 ","ENG":"Wow! I didn't expect to become the champion!\xA0","TWN":"哇～說實話，我沒想到能拿到第一名！"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_LAUGH"}}},"sfx":"FX_CUTSCEN_TADA"},{"id":"L18_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"크윽…… 이렇게까지 해도 진단 말이야?","JPN":"くうっ……ここまでやったのに負けたってこと？","ENG":"Kgh... We still lost?","TWN":"呃……做到這種地步還是不行嗎？"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"미안하다 얘들아. 내가 승부에는 좀 진지한 타입이라 그만 진심으로 해 버렸네.","JPN":"ごめんな、2人とも。勝負になるとつい本気になってしまうんや。","ENG":"I'm sorry, gals. I'm pretty serious about winning, so I didn't hold back.","TWN":"對不起，各位。我有點在意起勝負，不小心就認真起來了。"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"그래도 나중에 크면, 분명 나보다도 훨씬 강해질 수 있을기다.","JPN":"でも大人になったら、ウチよりきっと強くなれるで。","ENG":"But I'm sure you'll all become way stronger than me later down the road.","TWN":"不過等你長大後，一定會比我更強的。"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"그럼 다음에 보자. 또 조만간 볼 수 있겠지.","JPN":"ほなまたな。そのうち会えるやろ。","ENG":"I'll see y'all next time. Or maybe even sooner.","TWN":"那下次見，很快就能再見面吧。"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"거, 거기서! 난 아직 패배를 인정하지 않았다고!","JPN":"ま、待ちなさい！　私はまだ負けを認めていないわ！","ENG":"S-stop right there! I still haven't admitted defeat!","TWN":"站，站住！我還沒有認輸！"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"하하, 또 그런 소릴 하나?","JPN":"はは、またそれか。","ENG":"Haha, this again?","TWN":"哈哈，又在說那種話嗎？"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"그러고 보니 니랑은 서로 경쟁만 했지, 협력은 해본 적 없었네.","JPN":"そういえばあんたとは戦ってばかりで、協力したことはなかったな。","ENG":"Come to think of it, you and I have always fought and never cooperated.","TWN":"這麼說來，我和你一直在競爭，從未合作過呢。"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"잠깐 귀 한번 대봐.","JPN":"ちっと耳貸してみぃや。","ENG":"C'mere and lend me your ear.","TWN":"稍微靠近一點聽。"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L30_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"뭐, 뭐야……?","JPN":"な、何よ……？","ENG":"W-what...?","TWN":"什，什麼……？"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"지금 개네들, 엄~청나게 어려운 몬스터를 개발중이라 캤다.","JPN":"あいつら、今めっちゃ難しいモンスター開発中らしいで。","ENG":"Right now, Bora and Dain are developing a suuuuper strong monster.","TWN":"他們現在正在開發一個非常難對付的怪物。"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"출시하믄, 내랑 파티 함 안할래?","JPN":"リリースしたら、ウチとパーティー組まへん？","ENG":"Once it's released, wanna form a party with me?","TWN":"遊戲上線後，要不要和我一起組隊？"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"뭐?! 내가 왜 당신이랑……!","JPN":"はあ！？　なんで私があんたと……！","ENG":"What?! Why would I want to be in a party with you...?!","TWN":"什麼？！憑什麼我要跟你……！"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"이번에도 난 말해줬다. 선택은 니가 하는거지.","JPN":"とにかくウチは教えたで。選択するのはあんたや。","ENG":"Just tellin' ya. It's up to you.","TWN":"這次我也告訴你了，其他的你自己決定吧。"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L35_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"다인이 보라 말 잘 듣고, 다음에 만날 땐 강해져서 와라 알긋제?","JPN":"ほな、タエとシホの言うことよう聞くんやで。次会う時はもっと強くなってきぃや。","ENG":"Listen to Dain and Bora, and come back stronger the next time we meet, aight?","TWN":"多聽妲茵的話，下次見面時要變得更強喔，知道嗎？"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_WIND2"},{"id":"L37_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"하아?! 당신이 뭔데 나한테 이래라 저래라얏!!","JPN":"はあ！？　私に指図するんじゃないわよ！","ENG":"What?! Who are you to tell me what to do?!","TWN":"蛤？！你算什麼東西，竟敢對我指手畫腳！！"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};